1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
13	
14	const CURSED_SURCHARGE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_DISCOUNT_RATE = 0.2;
18	const LOYALTY_THRESHOLD_YEARS = 2;
19	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
20	
21	const COMPONENT_TYPES = ["rune", "moonstone"];
22	const BLOCK_SIZE = 3;
23	const BLOCK_PREMIUM = 60;
24	
25	const componentPremium = (type: string, count: number): number =>
26	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * basePremiumForType(type);
27	
28	const itemSurcharge = (item: any): number => {
29	  const base = basePremiumForType(item.type);
30	  let surcharge = 0;
31	  if (item.cursed) surcharge += base * CURSED_SURCHARGE_RATE;
32	  if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
33	  return surcharge;
34	};
35	
36	const calculateQuotePremium = (items: any[], customer: any): number => {
37	  const componentCounts: Record<string, number> = {};
38	  let policyBasePremium = 0;
39	  let itemSurcharges = 0;
40	  for (const item of items) {
41	    if (COMPONENT_TYPES.includes(item.type)) {
42	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
43	    } else {
44	      policyBasePremium += basePremiumForType(item.type);
45	      itemSurcharges += itemSurcharge(item);
46	    }
47	  }
48	  for (const [type, count] of Object.entries(componentCounts)) {
49	    policyBasePremium += componentPremium(type, count);
50	  }
51	  let premium = policyBasePremium + itemSurcharges;
52	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
53	    premium -= policyBasePremium * LOYALTY_DISCOUNT_RATE;
54	  }
55	  premium += policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
56	  return Math.ceil(premium + PROCESSING_FEE);
57	};
58	
59	export const processScenario = (scenario: any): any => ({
60	  results: scenario.steps.map((step: any) => ({
61	    premium: calculateQuotePremium(step.items, scenario.customer),
62	  })),
63	});
